    public Object parseDepositAddress(Object depositAddress, Object... optionalArgs)
    {
        //
        //     {
        //         "address": "1P1JqozxioQwaqPwgMAQdNDYNyaVSqgARq",
        //         "memo": ""
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object coinAddress = this.safeString(depositAddress, "address");
        Object parts = Helpers.split(coinAddress, ":");
        Object address = null;
        Object tag = null;
        Object partsLength = Helpers.getArrayLength(parts);
        if (Helpers.isTrue(Helpers.isTrue(Helpers.isGreaterThan(partsLength, 1)) && Helpers.isTrue(!Helpers.isEqual(Helpers.GetValue(parts, 0), "cfx"))))
        {
            address = Helpers.GetValue(parts, 0);
            tag = Helpers.GetValue(parts, 1);
        } else
        {
            address = coinAddress;
        }
        final Object finalAddress = address;
        final Object finalTag = tag;
        return new java.util.HashMap<String, Object>() {{
            put( "info", depositAddress );
            put( "currency", CoinexCore.this.safeCurrencyCode(null, currency) );
            put( "network", null );
            put( "address", finalAddress );
            put( "tag", CoinexCore.this.safeString(depositAddress, "memo", finalTag) );
        }};
    }

