    public Object parseFundingRate(Object contract, Object... optionalArgs)
    {
        //
        // fetchFundingRate, fetchFundingRates, fetchFundingInterval
        //
        //     {
        //         "latest_funding_rate": "0",
        //         "latest_funding_time": 1715731200000,
        //         "mark_price": "61602.22",
        //         "market": "BTCUSDT",
        //         "max_funding_rate": "0.00375",
        //         "min_funding_rate": "-0.00375",
        //         "next_funding_rate": "0.00021074",
        //         "next_funding_time": 1715760000000
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object currentFundingTimestamp = this.safeInteger(contract, "latest_funding_time");
        Object futureFundingTimestamp = this.safeInteger(contract, "next_funding_time");
        Object fundingTimeString = this.safeString(contract, "latest_funding_time");
        Object nextFundingTimeString = this.safeString(contract, "next_funding_time");
        Object millisecondsInterval = Precise.stringSub(nextFundingTimeString, fundingTimeString);
        Object marketId = this.safeString(contract, "market");
        return new java.util.HashMap<String, Object>() {{
            put( "info", contract );
            put( "symbol", CoinexCore.this.safeSymbol(marketId, market, null, "swap") );
            put( "markPrice", CoinexCore.this.safeNumber(contract, "mark_price") );
            put( "indexPrice", null );
            put( "interestRate", null );
            put( "estimatedSettlePrice", null );
            put( "timestamp", null );
            put( "datetime", null );
            put( "fundingRate", CoinexCore.this.safeNumber(contract, "latest_funding_rate") );
            put( "fundingTimestamp", currentFundingTimestamp );
            put( "fundingDatetime", CoinexCore.this.iso8601(currentFundingTimestamp) );
            put( "nextFundingRate", CoinexCore.this.safeNumber(contract, "next_funding_rate") );
            put( "nextFundingTimestamp", futureFundingTimestamp );
            put( "nextFundingDatetime", CoinexCore.this.iso8601(futureFundingTimestamp) );
            put( "previousFundingRate", null );
            put( "previousFundingTimestamp", null );
            put( "previousFundingDatetime", null );
            put( "interval", CoinexCore.this.parseFundingInterval(millisecondsInterval) );
        }};
    }

    public Object parseFundingInterval(Object interval)
    {
        Object intervals = new java.util.HashMap<String, Object>() {{
            put( "3600000", "1h" );
            put( "14400000", "4h" );
            put( "28800000", "8h" );
            put( "57600000", "16h" );
            put( "86400000", "24h" );
        }};
        return this.safeString(intervals, interval, interval);
    }

