    /**
     * @method
     * @name coinex#fetchDepositWithdrawFees
     * @description fetch the fees for deposits and withdrawals
     * @see https://docs.coinex.com/api/v2/assets/deposit-withdrawal/http/list-all-deposit-withdrawal-config
     * @param {string[]} [codes] list of unified currency codes
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a dictionary of [fee structures]{@link https://docs.ccxt.com/?id=fee-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchDepositWithdrawFees(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object codes = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object response = (this.v2PublicGetAssetsAllDepositWithdrawConfig(parameters)).join();
            //
            //     {
            //         "code": 0,
            //         "data": [
            //             {
            //                 "asset": {
            //                     "ccy": "CET",
            //                     "deposit_enabled": true,
            //                     "withdraw_enabled": true,
            //                     "inter_transfer_enabled": true,
            //                     "is_st": false
            //                 },
            //                 "chains": [
            //                     {
            //                         "chain": "CSC",
            //                         "min_deposit_amount": "0.8",
            //                         "min_withdraw_amount": "8",
            //                         "deposit_enabled": true,
            //                         "withdraw_enabled": true,
            //                         "deposit_delay_minutes": 0,
            //                         "safe_confirmations": 10,
            //                         "irreversible_confirmations": 20,
            //                         "deflation_rate": "0",
            //                         "withdrawal_fee": "0.026",
            //                         "withdrawal_precision": 8,
            //                         "memo": "",
            //                         "is_memo_required_for_deposit": false,
            //                         "explorer_asset_url": ""
            //                     },
            //                 ]
            //             }
            //         ],
            //         "message": "OK"
            //     }
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object result = new java.util.HashMap<String, Object>() {{}};
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
            {
                Object item = Helpers.GetValue(data, i);
                Object asset = this.safeDict(item, "asset", new java.util.HashMap<String, Object>() {{}});
                Object currencyId = this.safeString(asset, "ccy");
                if (Helpers.isTrue(Helpers.isEqual(currencyId, null)))
                {
                    continue;
                }
                Object code = this.safeCurrencyCode(currencyId);
                if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(codes, null)) || Helpers.isTrue(this.inArray(code, codes))))
                {
                    Helpers.addElementToObject(result, code, this.parseDepositWithdrawFee(item));
                }
            }
            return result;
        });

    }

    public Object parseDepositWithdrawFee(Object fee, Object... optionalArgs)
    {
        //
        //     {
        //         "asset": {
        //             "ccy": "USDT",
        //             "deposit_enabled": true,
        //             "withdraw_enabled": true,
        //             "inter_transfer_enabled": true,
        //             "is_st": false
        //         },
        //         "chains": [
        //             {
        //                 "chain": "TRC20",
        //                 "min_deposit_amount": "2.4",
        //                 "min_withdraw_amount": "2.4",
        //                 "deposit_enabled": true,
        //                 "withdraw_enabled": true,
        //                 "deposit_delay_minutes": 0,
        //                 "safe_confirmations": 10,
        //                 "irreversible_confirmations": 20,
        //                 "deflation_rate": "0",
        //                 "withdrawal_fee": "2.4",
        //                 "withdrawal_precision": 6,
        //                 "memo": "",
        //                 "is_memo_required_for_deposit": false,
        //                 "explorer_asset_url": "https://tronscan.org/#/token20/TR7NHqjeKQxGTCi8q8ZY4pL8otSzgjLj6t"
        //             },
        //         ]
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", fee );
            put( "withdraw", new java.util.HashMap<String, Object>() {{
                put( "fee", null );
                put( "percentage", null );
            }} );
            put( "deposit", new java.util.HashMap<String, Object>() {{
                put( "fee", null );
                put( "percentage", null );
            }} );
            put( "networks", new java.util.HashMap<String, Object>() {{}} );
        }};
        Object chains = this.safeList(fee, "chains", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object asset = this.safeDict(fee, "asset", new java.util.HashMap<String, Object>() {{}});
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(chains)); i++)
        {
            Object entry = Helpers.GetValue(chains, i);
            Object isWithdrawEnabled = this.safeBool(entry, "withdraw_enabled");
            if (Helpers.isTrue(isWithdrawEnabled))
            {
                Helpers.addElementToObject(Helpers.GetValue(result, "withdraw"), "fee", this.safeNumber(entry, "withdrawal_fee"));
                Helpers.addElementToObject(Helpers.GetValue(result, "withdraw"), "percentage", false);
                Object networkId = this.safeString(entry, "chain");
                if (Helpers.isTrue(networkId))
                {
                    Object currencyId = this.safeString(asset, "ccy");
                    Object feeCode = this.safeCurrencyCode(currencyId, currency);
                    Object networkCode = this.networkIdToCode(networkId, feeCode);
                    Helpers.addElementToObject(Helpers.GetValue(result, "networks"), networkCode, new java.util.HashMap<String, Object>() {{
    put( "withdraw", new java.util.HashMap<String, Object>() {{
        put( "fee", CoinexCore.this.safeNumber(entry, "withdrawal_fee") );
        put( "percentage", false );
    }} );
    put( "deposit", new java.util.HashMap<String, Object>() {{
        put( "fee", null );
        put( "percentage", null );
    }} );
}});
                }
            }
        }
        return result;
    }

