            //                 "margin_change": "-1.5",
            //                 "margin_mode": "isolated",
            //                 "market": "BTCUSDT",
            //                 "market_type": "FUTURES",
            //                 "open_interest": "0.0001",
            //                 "position_id": 306458800,
            //                 "settle_price": "61047.84"
            //             },
            //         ],
            //         "message": "OK",
            //         "pagination": {
            //             "has_next": true
